// Cargador de @zxing/browser desde CDN. Garantiza que window.ZXingBrowser exista.
(function loadZXing(){
  var s = document.createElement('script');
  s.src = 'https://unpkg.com/@zxing/browser@0.1.5/umd/zxing-browser.min.js';
  s.async = true;
  s.onload = function(){ window.__ZXING_READY__ = true; document.dispatchEvent(new Event('zxing-ready')); };
  s.onerror = function(){ console.error('ZXing no se pudo cargar — verifica tu conexión.'); };
  document.head.appendChild(s);
})();
